"use client";

import { useState } from "react";
import Image from "next/image";
import { useParams } from "next/navigation";
import { products } from "@/data/products";
import { apiRequest } from "@/lib/api";
import { useAuth } from "@/context/AuthContext";

export default function ProductDetail() {
  const { id } = useParams<{ id: string }>(); // ✅ FIX
  const product = products.find((p) => p.id === id);
  const { token } = useAuth();

  const [selectedImage, setSelectedImage] = useState(0);
  const [deliveryType, setDeliveryType] = useState<"shipping" | "pickup">(
    "shipping"
  );
  const [address, setAddress] = useState("");
  const [customText, setCustomText] = useState("");
  const [loading, setLoading] = useState(false);

  if (!product) {
    return <div className="px-6 py-32">Product not found</div>;
  }

  const handleOrder = async () => {
    if (!token) {
      alert("Please login first");
      return;
    }

    try {
      setLoading(true);
      await apiRequest(
        "/orders",
        "POST",
        {
          shippingAddress:
            deliveryType === "shipping" ? address : "Store Pickup",
          price: product.price,
        },
        token
      );
      alert("Order created successfully");
    } catch (err: any) {
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="px-6 py-32 max-w-6xl mx-auto grid lg:grid-cols-2 gap-16">
      
      {/* LEFT — IMAGES */}
      <div>
        <div className="relative aspect-[4/5] mb-6">
          <Image
            src={product.images[selectedImage]}
            alt={product.name}
            fill
            className="object-cover"
          />
        </div>

        <div className="flex gap-4">
          {product.images.map((img, i) => (
            <button
              key={i}
              onClick={() => setSelectedImage(i)}
              className={`relative w-20 aspect-square border ${
                selectedImage === i
                  ? "border-black"
                  : "border-black/30"
              }`}
            >
              <Image src={img} alt="" fill className="object-cover" />
            </button>
          ))}
        </div>
      </div>

      {/* RIGHT — DETAILS */}
      <div>
        <h1 className="font-[var(--font-serif)] text-4xl mb-4">
          {product.name}
        </h1>

        <p className="text-xl mb-6">₹{product.price}</p>

        <div className="mb-6">
          <label className="block text-sm mb-2">
            Custom text for product
          </label>
          <textarea
            className="w-full border border-black/30 p-3"
            rows={3}
            value={customText}
            onChange={(e) => setCustomText(e.target.value)}
          />
        </div>

        <p className="mb-6 text-sm opacity-80">
          Estimated delivery: <strong>{product.delivery}</strong>
        </p>

        <div className="mb-6 space-y-3">
          <label className="flex items-center gap-2">
            <input
              type="radio"
              checked={deliveryType === "shipping"}
              onChange={() => setDeliveryType("shipping")}
            />
            Shipping
          </label>

          <label className="flex items-center gap-2">
            <input
              type="radio"
              checked={deliveryType === "pickup"}
              onChange={() => setDeliveryType("pickup")}
            />
            Pick up from store
          </label>
        </div>

        {deliveryType === "shipping" && (
          <div className="mb-6">
            <label className="block text-sm mb-2">
              Shipping Address
            </label>
            <textarea
              className="w-full border border-black/30 p-3"
              rows={3}
              value={address}
              onChange={(e) => setAddress(e.target.value)}
            />
          </div>
        )}

        <button
          onClick={handleOrder}
          disabled={loading}
          className="mt-6 border border-black px-10 py-3 uppercase tracking-widest text-sm disabled:opacity-50"
        >
          {loading ? "Placing order..." : "Add to Order"}
        </button>
      </div>
    </main>
  );
}